 1	import React from 'react';
 2	import classnames from 'classnames';
 3	
 4	import {
 5	  V1beta1DataImportCron,
 6	  V1beta1DataSource,
 7	} from '@kubevirt-ui/kubevirt-api/containerized-data-importer/models';
 8	import MutedTextSpan from '@kubevirt-utils/components/MutedTextSpan/MutedTextSpan';
 9	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
10	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
11	import {
12	  ClipboardCopy,
13	  DescriptionList,
14	  DescriptionListDescription,
15	  DescriptionListGroup,
16	  DescriptionListTerm,
17	} from '@patternfly/react-core';
18	
19	import { isDataImportCronAutoUpdated, isDataResourceOwnedBySSP } from '../../../utils';
20	
21	import './DataImportCronManageDetails.scss';
22	
23	type DataImportCronManageDetailsProps = {
24	  dataImportCron: V1beta1DataImportCron;
25	  dataSource: V1beta1DataSource;
26	  onEditClick: () => void;
27	};
28	
29	export const DataImportCronManageDetails: React.FC<DataImportCronManageDetailsProps> = ({
30	  dataImportCron,
31	  dataSource,
32	  onEditClick,
33	}) => {
34	  const { t } = useKubevirtTranslation();
35	
36	  const source = dataImportCron?.spec?.template.spec?.source?.registry?.url;
37	  const importsToKeep = dataImportCron?.spec?.importsToKeep?.toString() || t('3 (default)');
38	  const isAutoUpdated = isDataImportCronAutoUpdated(dataSource, dataImportCron);
39	  const isOwnedBySSP = isDataResourceOwnedBySSP(dataImportCron);
40	
41	  return (
42	    <VirtualMachineDescriptionItem
43	      descriptionData={
44	        <DescriptionList
45	          className={classnames('pf-v6-c-description-list', 'kv-dataimportcron-managed-details')}
46	        >
47	          <VirtualMachineDescriptionItem
48	            descriptionData={isAutoUpdated ? t('On') : t('Off')}
49	            descriptionHeader={t('Automatic updates')}
50	          />
51	          <VirtualMachineDescriptionItem
52	            descriptionData={source ?? <MutedTextSpan text={t('Not available')} />}
53	            descriptionHeader={t('Source')}
54	          />
55	          <VirtualMachineDescriptionItem
56	            descriptionData={importsToKeep}
57	            descriptionHeader={t('Retain revisions')}
58	          />
59	          <VirtualMachineDescriptionItem
60	            descriptionData={
61	              <DescriptionList className="pf-v6-c-description-list" isHorizontal>
62	                <DescriptionListGroup>
63	                  <DescriptionListTerm>{t('Cron expression')}</DescriptionListTerm>
64	                  <DescriptionListDescription>
65	                    <ClipboardCopy
66	                      clickTip={t('Copied')}
67	                      data-test="cron-copy-command"
68	                      hoverTip={t('Copy to clipboard')}
69	                      isReadOnly
70	                    >
71	                      {dataImportCron?.spec?.schedule}
72	                    </ClipboardCopy>
73	                  </DescriptionListDescription>
74	                </DescriptionListGroup>
75	              </DescriptionList>
76	            }
77	            descriptionHeader={t('Scheduling settings')}
78	          />
79	        </DescriptionList>
80	      }
81	      data-test-id="dataimportcron-manage-details"
82	      descriptionHeader={t('Automatic update and scheduling')}
83	      isEdit={!isOwnedBySSP}
84	      onEditClick={onEditClick}
85	      showEditOnTitle
86	    />
87	  );
88	};

